var inputItems = $input.all();
var outputItems = [];
for (var itemIndex = 0; itemIndex < inputItems.length; itemIndex += 1) {
  var currentItem = inputItems[itemIndex] || {};
  var sourceJson = currentItem.json || {};
  var sourceBinary = currentItem.binary || {};
  var binaryKeys = Object.keys(sourceBinary);
  for (var keyIndex = 0; keyIndex < binaryKeys.length; keyIndex += 1) {
    var binaryKey = binaryKeys[keyIndex];
    var file = sourceBinary[binaryKey] || {};
    var fileName = String(file.fileName || '').toLowerCase();
    var mimeType = String(file.mimeType || '').toLowerCase();
    if (mimeType === 'application/pdf' || fileName.endsWith('.pdf')) {
      outputItems.push({
        json: {
          source_filename: file.fileName || ('email-attachment-' + keyIndex + '.pdf'),
          ingestion_channel: 'email',
          received_date: sourceJson.date || sourceJson.receivedDate || sourceJson.sentDate || sourceJson.internalDate || null,
          duplicate_mode: 'overwrite',
          persist_result: true,
          persistence_mode: 'postgres',
          email_subject: sourceJson.subject || null,
          email_from: sourceJson.from || null
        },
        binary: {
          pdf: file
        }
      });
    }
  }
}
return outputItems;
